mapper.select:
SELECT wla.id AS id, wla.work_log_id AS workLogId, wla.attachment_id AS attachmentId, wla.sort AS sort, wla.created_at AS createdAt, a.id AS att_id, a.original_name AS att_originalName, a.mime_type AS att_mimeType, a.size AS att_size, a.created_at AS att_createTime FROM work_log_attachment wla INNER JOIN attachment a ON wla.attachment_id = a.id AND a.deleted_at IS NULL WHERE wla.work_log_id IN
#{wid}
ORDER BY wla.work_log_id ASC, wla.sort ASC

SELECT tca.id AS id, tca.comment_id AS commentId, tca.attachment_id AS attachmentId, tca.sort AS sort, tca.created_at AS createdAt, a.id AS att_id, a.original_name AS att_originalName, a.mime_type AS att_mimeType, a.size AS att_size, a.created_at AS att_createTime FROM task_comment_attachment tca INNER JOIN attachment a ON tca.attachment_id = a.id AND a.deleted_at IS NULL WHERE tca.comment_id IN
#{cid}
ORDER BY tca.comment_id ASC, tca.sort ASC
